INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1000, "vo_minigame_1013_icon_1_002_001", "調子が上がって\nきたなっ", 2, "vo_minigame_1013_icon_2_002_001", 2, "訓練はまだ\nここからですわ", 1, 3000, 2);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (5000, "vo_minigame_1013_icon_1_003_001", "ほらほら、\nまだいけるだろ？", 2, "vo_minigame_1013_icon_2_003_001", 2, "クスクス、悪くない\n流れですわね", 2, 3000, 2);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_004_001", "へへっ、おまえら\nやるじゃねえか！", 2, "vo_minigame_1013_icon_2_004_001", 2, "すばらしい\n記録ですわ", 3, 3000, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_001", "あたしたちはまだ\n止まらねえぜ！", 2, "vo_minigame_1013_icon_2_005_001", 3, "乗りに乗って\nいますわね", 4, 3000, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_002", "見てろよ！\nマコト班の快進撃だ！", 2, "vo_minigame_1013_icon_2_005_002", 3, "まだまだ行きます\nついてきなさい", 5, 3000, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_003", "うおぉぉっ！\n絶好調だぜ！", 2, "vo_minigame_1013_icon_2_005_003", 3, "エリコ班の\n本領発揮ですわ！", 6, 3000, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (0, "vo_minigame_1013_icon_1_006_001", "どこまで行けるか\n楽しみだなっ！", 2, "vo_minigame_1013_icon_2_006_001", 4, "ここからは\n前人未到の領域です！", 7, 3000, 3);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_001", "まだ諦めんなよっ", 3, "vo_minigame_1013_icon_2_007_001", 5, "厄介でしたわ…", 8, 1000, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_002", "冷やっとしたぜ…！", 3, "vo_minigame_1013_icon_2_007_002", 5, "油断大敵です", 9, 1000, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_003", "弱音を吐くなっ", 3, "vo_minigame_1013_icon_2_007_003", 5, "忌々しいっ…", 10, 1000, 4);
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (99, "vo_minigame_1013_icon_1_008_001", "マコト班集合！", 4, "vo_minigame_1013_icon_2_008_001", 6, "大所帯ですわね", 11, 1500, 3);
